            classReader.accept(classRenamer, 0);

            // 输出修改后的类
            try (FileOutputStream fos = new FileOutputStream(targetClassFile)) {
                fos.write(classWriter.toByteArray());
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
```

